    key_points: ['Self-awareness', 'Learning from mistakes', 'Growth mindset', 'Accountability']
  },
  {
    id: 'beh-3',
    category: 'behavioral',
    difficulty: 'Hard',
    question: 'Tell me about a time when you had to make a difficult decision with incomplete information.',
